import{_ as e,o as r,c as t,ag as o}from"./chunks/framework.DNmTgtHf.js";const u=JSON.parse('{"title":"改善既有代码的设计","description":"改善既有代码的设计","frontmatter":{"title":"改善既有代码的设计","description":"改善既有代码的设计","tags":["技术文档"]},"headers":[],"relativePath":"docs/notes/02-改善既有代码的设计.md","filePath":"docs/notes/02-改善既有代码的设计.md","lastUpdated":1782292064000}'),h={name:"docs/notes/02-改善既有代码的设计.md"};function i(l,a,n,d,s,p){return r(),t("div",null,[...a[0]||(a[0]=[o('<h2 id="书籍推荐" tabindex="-1">书籍推荐 <a class="header-anchor" href="#书籍推荐" aria-label="Permalink to &quot;书籍推荐&quot;">​</a></h2><p><a href="https://github.com/jf652366/expert_readed_books/blob/master/%E7%BC%96%E7%A8%8B%E6%80%9D%E6%83%B3%E7%B1%BB/%E4%BF%AE%E6%94%B9%E4%BB%A3%E7%A0%81%E7%9A%84%E8%89%BA%E6%9C%AF(%E4%B8%AD%E6%96%87pdf%E7%89%88).pdf" target="_blank" rel="noreferrer">修改代码的艺术</a></p><h2 id="重构的原则" tabindex="-1">重构的原则 <a class="header-anchor" href="#重构的原则" aria-label="Permalink to &quot;重构的原则&quot;">​</a></h2><h3 id="何时重构" tabindex="-1">何时重构 <a class="header-anchor" href="#何时重构" aria-label="Permalink to &quot;何时重构&quot;">​</a></h3><p>何时重构：第一次去做时只管去做，第二次做类似的事情，会反感但是无论如何还是可以做，第三次再做类似的事，就应该重构。</p><h4 id="预备性重构-让添加新功能更容易" tabindex="-1">预备性重构：让添加新功能更容易 <a class="header-anchor" href="#预备性重构-让添加新功能更容易" aria-label="Permalink to &quot;预备性重构：让添加新功能更容易&quot;">​</a></h4><p>在动手添加新功能之前，先看看现有代码，如果发现对代码结构做一点微调，工作会容易很多 。</p><h4 id="帮助理解的重构-让代码更易懂" tabindex="-1">帮助理解的重构：让代码更易懂 <a class="header-anchor" href="#帮助理解的重构-让代码更易懂" aria-label="Permalink to &quot;帮助理解的重构：让代码更易懂&quot;">​</a></h4><p>修改代码时需要思考这段代码到底在做什么，发现需要好几分钟才能搞懂到底它在做什么。</p><h4 id="捡垃圾式重构" tabindex="-1">捡垃圾式重构 <a class="header-anchor" href="#捡垃圾式重构" aria-label="Permalink to &quot;捡垃圾式重构&quot;">​</a></h4><p>我已经理解代码在做什么，但发现它做的不够好，如果发现只需要进行简单修改，那么应该马上重构，如果发现需要花一些精力，那么应该记下来，完成当下任务时再回来重构，至少要让代码比之前更好，即便修改的不完整，那么代码也不会被破坏。</p><h4 id="有计划的重构和见机行事的重构" tabindex="-1">有计划的重构和见机行事的重构 <a class="header-anchor" href="#有计划的重构和见机行事的重构" aria-label="Permalink to &quot;有计划的重构和见机行事的重构&quot;">​</a></h4><p>见机行事的重构：预备性修复、帮助理解的重构、捡垃圾式的重构。</p><p>有计划的重构：专门安排时间重构。</p><h4 id="长期重构" tabindex="-1">长期重构 <a class="header-anchor" href="#长期重构" aria-label="Permalink to &quot;长期重构&quot;">​</a></h4><p>如果遇到需要替换一个正在使用的库，应该让整个团队达成共识，每当有人靠近“重构区”的时候，就把它朝着想要的方向改进，好处在于每次小改动之后，整个系统仍然可以正常工作。具体做法可以先引入一层新的抽象，使其兼容新旧两个库的接口，一旦调用方完全改为使用这层抽象，那么替换新的库就会容易很多</p><h4 id="复审代码时重构" tabindex="-1">复审代码时重构 <a class="header-anchor" href="#复审代码时重构" aria-label="Permalink to &quot;复审代码时重构&quot;">​</a></h4><p>最舒服的方式为和原作者坐在一起，一边浏览代码，一边重构</p><h4 id="怎么对经理说" tabindex="-1">怎么对经理说 <a class="header-anchor" href="#怎么对经理说" aria-label="Permalink to &quot;怎么对经理说&quot;">​</a></h4><p>如果经理懂技术，能理解“设计耐久性假说”，那么应该很好说服，如果不具备技术意识，那么应该不告诉经理，实现新功能的最快方式就是重构</p><h4 id="何时不应该重构" tabindex="-1">何时不应该重构 <a class="header-anchor" href="#何时不应该重构" aria-label="Permalink to &quot;何时不应该重构&quot;">​</a></h4><p>如果一块凌乱的代码不需要修改他那么久可以不用进行重构，只有需要理解其工作原理时，对其重构才有价值。</p><p>如果重写比重构还容易，那么直接重写。</p><h3 id="重构的挑战" tabindex="-1">重构的挑战 <a class="header-anchor" href="#重构的挑战" aria-label="Permalink to &quot;重构的挑战&quot;">​</a></h3><h4 id="延缓新功能开发" tabindex="-1">延缓新功能开发 <a class="header-anchor" href="#延缓新功能开发" aria-label="Permalink to &quot;延缓新功能开发&quot;">​</a></h4><p>重构的唯一目的就是让开发更快，用更少的工作量创造更大的价值</p><p>一块代码很少触碰，不会经常带来麻烦不倾向于重构，没想清楚如何优化代码，应该延迟重构，活着先做一些实验，看看能否有所改经。</p><h4 id="测试" tabindex="-1">测试 <a class="header-anchor" href="#测试" aria-label="Permalink to &quot;测试&quot;">​</a></h4><p>不改变程序的可观察性行为（重构重要特征）</p><p>想要做到快发现错误，那么代码中应该有一套完备的测试套件，并且速度要快，绝大多数情况下，如果想要重构，得先有一套可以自测试的代码。</p><h4 id="遗留代码" tabindex="-1">遗留代码 <a class="header-anchor" href="#遗留代码" aria-label="Permalink to &quot;遗留代码&quot;">​</a></h4><p>重构可以帮助理解遗留代码，</p>',32)])])}const b=e(h,[["render",i]]);export{u as __pageData,b as default};
